class Solution:
    def minSteps(self, s: str, t: str) -> int:
        count_s = {}
        count_t = {}

        for char in s:
            if char in count_s:
                count_s[char] += 1
            else:
                count_s[char] = 1

        for char in t:
            if char in count_t:
                count_t[char] += 1
            else:
                count_t[char] = 1

        steps = 0
        for key in count_s:
            if key in count_t:
                steps += abs(count_s[key] - count_t[key])
            else:
                steps += count_s[key]

        return steps
